//* ---- EXPORT HTML POUR FITCOACH ---- */

function slugify(text) {
  return String(text || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .replace(/-+/g, "-");
}

function injectValuesInHTML() {
  const clone = document.documentElement.cloneNode(true);

  const realElements = document.documentElement.querySelectorAll("input, textarea, select");
  const cloneElements = clone.querySelectorAll("input, textarea, select");

  realElements.forEach((el, index) => {
    const cloneEl = cloneElements[index];
    if (!cloneEl) return;

    const tag = el.tagName.toLowerCase();

    if (tag === "input") {
      const type = (el.getAttribute("type") || "").toLowerCase();

      if (type === "checkbox" || type === "radio") {
        if (el.checked) {
          cloneEl.setAttribute("checked", "checked");
        } else {
          cloneEl.removeAttribute("checked");
        }
      } else {
        cloneEl.setAttribute("value", el.value || "");
      }
    }

    if (tag === "textarea") {
      cloneEl.setAttribute("value", el.value || "");
      cloneEl.textContent = el.value || "";
    }

    if (tag === "select") {
      const cloneOptions = cloneEl.querySelectorAll("option");
      cloneOptions.forEach((opt) => opt.removeAttribute("selected"));

      const selectedValue = el.value;
      const matchingOption = Array.from(cloneOptions).find(
        (opt) => opt.value === selectedValue
      );

      if (matchingOption) {
        matchingOption.setAttribute("selected", "selected");
      }
    }
  });

  return "<!DOCTYPE html>\n" + clone.outerHTML;
}

function exportHTML() {
  const htmlString = injectValuesInHTML();

  const progNameInput = document.getElementById("prog-name");
  const rawName = progNameInput ? progNameInput.value : "programme";
  const fileName = (slugify(rawName) || "programme") + ".html";

  const blob = new Blob([htmlString], { type: "text/html;charset=utf-8" });
  const url = URL.createObjectURL(blob);

  const a = document.createElement("a");
  a.href = url;
  a.download = fileName;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);

  setTimeout(() => {
    URL.revokeObjectURL(url);
  }, 1000);
}
